def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        factor = 1
        for j in range(1, 8):
            if j % 2 == 0:
                factor *= 0.9
            else:
                factor *= 1.1
            if ratio < 0.1 * j:
                contribution = (np.sin(j * ratio) + np.cos(factor * ratio)) * (j ** 1.5)
            else:
                contribution = (np.log1p(j * ratio) - np.sqrt(factor + ratio)) * (j ** 1.2)
            score += contribution
        if cap < item * 3:
            score *= 2.0
            for k in range(1, 4):
                score += np.exp(-k * ratio) * cap / (k + 1)
        elif cap > item * 6:
            score /= (cap / item)
            for k in range(1, 3):
                score -= (np.tanh(ratio * k) * (cap % (k+2)))
        else:
            for k in range(1, 5):
                if cap % k == 0:
                    score += np.sqrt(k * ratio)
                else:
                    score -= np.log1p(k * ratio)
        if score < 0:
            priorities[i] = np.abs(score) / (cap + 1)
        else:
            priorities[i] = -score / (np.sqrt(cap) + 1)
    return priorities
